// /frontend/src/components/Radar.jsx
import React, { useEffect, useRef, useState } from "react";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

/**
 * Provider priority (auto):
 * 1) Iowa State Mesonet NEXRAD composite (fast + reliable, no API key)
 * 2) RainViewer latest frame (public metadata)
 * 3) OpenWeather precipitation tiles (requires key)
 *
 * The first provider to successfully load a tile "wins".
 * You can also switch manually with the buttons.
 */

const OWM_KEY = process.env.REACT_APP_OWM_KEY || import.meta?.env?.VITE_OWM_KEY || "";
const CENTER = [33.749, -84.388];
const ZOOM = 6;

const PROVIDERS = {
  mesonet: {
    label: "Mesonet",
    // Base reflectivity composite, Web Mercator
    url: "https://mesonet.agron.iastate.edu/cache/tile.py/1.0.0/nexrad-n0q-900913/{z}/{x}/{y}.png",
    opts: { opacity: 0.85, zIndex: 500, crossOrigin: true },
  },
  rainviewer: {
    label: "RainViewer",
    dynamic: true, // needs metadata to get latest timestamp
  },
  owm: {
    label: "OWM",
    url: OWM_KEY
      ? `https://tile.openweathermap.org/map/precipitation_new/{z}/{x}/{y}.png?appid=${OWM_KEY}`
      : "",
    opts: { opacity: 0.85, zIndex: 500, crossOrigin: true },
  },
};

export default function Radar() {
  const mapRef = useRef(null);
  const activeLayerRef = useRef(null);
  const [loading, setLoading] = useState(true);
  const [errorText, setErrorText] = useState("");
  const [active, setActive] = useState(""); // which provider actually won
  const [manual, setManual] = useState(""); // manual selection, overrides auto

  // initialize map once
  useEffect(() => {
    if (mapRef.current) return;
    const map = L.map("radar-map", {
      zoomControl: false,
      attributionControl: false,
      preferCanvas: true,
    }).setView(CENTER, ZOOM);

    L.tileLayer(
      "https://{s}.tile.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png",
      { subdomains: "abcd", maxZoom: 18, opacity: 0.95 }
    ).addTo(map);

    mapRef.current = map;
    setTimeout(() => map.invalidateSize(), 0);
  }, []);

  // helper: set a new layer as the only active one
  const setActiveLayer = (layer, providerId) => {
    const map = mapRef.current;
    if (!map) return;
    if (activeLayerRef.current) {
      try { map.removeLayer(activeLayerRef.current); } catch {}
    }
    activeLayerRef.current = layer.addTo(map);
    setActive(providerId);
    setLoading(false);
    setErrorText("");
  };

  // load RainViewer latest frame
  const createRainviewerLayer = async () => {
    try {
      const meta = await fetch("https://api.rainviewer.com/public/weather-maps.json").then(r => r.json());
      const host = meta?.host || "";
      const frames = [...(meta?.radar?.past || []), ...(meta?.radar?.nowcast || [])];
      const last = frames.at(-1)?.time;
      if (!host || !last) throw new Error("No RainViewer frames");
      return L.tileLayer(`${host}/v2/radar/${last}/256/{z}/{x}/{y}.png`, {
        opacity: 0.85, zIndex: 500, crossOrigin: true
      });
    } catch (e) {
      throw new Error("RainViewer metadata unavailable");
    }
  };

  // AUTO mode: race providers; first to load a tile wins
  useEffect(() => {
    if (!mapRef.current || manual) return;

    let cancelled = false;
    setLoading(true);
    setErrorText("");
    setActive("");

    const map = mapRef.current;
    const contestants = [];

    const onWin = (layer, id) => {
      if (cancelled) return;
      // clear losers
      contestants.forEach(c => {
        if (c.layer && c.id !== id) {
          try { map.removeLayer(c.layer); } catch {}
        }
      });
      setActiveLayer(layer, id);
    };

    // Start Mesonet immediately
    const meso = L.tileLayer(PROVIDERS.mesonet.url, PROVIDERS.mesonet.opts)
      .on("load", () => onWin(meso, "mesonet"))
      .on("tileerror", () => {}) // ignore; other providers may win
      .addTo(map);
    contestants.push({ id: "mesonet", layer: meso });

    // Start RainViewer
    (async () => {
      try {
        const rv = await createRainviewerLayer();
        if (cancelled) return;
        rv.on("load", () => onWin(rv, "rainviewer"))
          .on("tileerror", () => {});
        rv.addTo(map);
        contestants.push({ id: "rainviewer", layer: rv });
      } catch {
        // no-op; other providers can still win
      }
    })();

    // Start OWM if key present
    if (PROVIDERS.owm.url) {
      const owm = L.tileLayer(PROVIDERS.owm.url, PROVIDERS.owm.opts)
        .on("load", () => onWin(owm, "owm"))
        .on("tileerror", () => {});
      owm.addTo(map);
      contestants.push({ id: "owm", layer: owm });
    }

    // Safety timeout: if nothing loads in 5s, show message
    const to = setTimeout(() => {
      if (!cancelled && !activeLayerRef.current) {
        setLoading(false);
        setErrorText("Radar tiles didn’t load. It may be a network or provider issue.");
      }
    }, 5000);

    return () => {
      cancelled = true;
      clearTimeout(to);
      contestants.forEach(c => {
        try { map.removeLayer(c.layer); } catch {}
      });
    };
  }, [manual]);

  // MANUAL switcher: replace current layer with chosen provider
  useEffect(() => {
    if (!manual) return;
    const map = mapRef.current;
    if (!map) return;

    setLoading(true);
    setErrorText("");

    // remove current
    if (activeLayerRef.current) {
      try { map.removeLayer(activeLayerRef.current); } catch {}
      activeLayerRef.current = null;
    }

    let layer;
    let cancelled = false;

    const finish = (lyr, id) => {
      if (cancelled) return;
      setActiveLayer(lyr, id);
    };

    const fail = (msg) => {
      if (cancelled) return;
      setLoading(false);
      setErrorText(msg);
    };

    (async () => {
      try {
        if (manual === "mesonet") {
          layer = L.tileLayer(PROVIDERS.mesonet.url, PROVIDERS.mesonet.opts)
            .on("load", () => finish(layer, "mesonet"))
            .on("tileerror", () => fail("Mesonet tiles failed to load."));
          layer.addTo(map);
        } else if (manual === "rainviewer") {
          layer = await createRainviewerLayer();
          layer
            .on("load", () => finish(layer, "rainviewer"))
            .on("tileerror", () => fail("RainViewer tiles failed to load."));
          layer.addTo(map);
        } else if (manual === "owm") {
          if (!PROVIDERS.owm.url) return fail("OWM key missing.");
          layer = L.tileLayer(PROVIDERS.owm.url, PROVIDERS.owm.opts)
            .on("load", () => finish(layer, "owm"))
            .on("tileerror", () => fail("OWM tiles failed to load."));
          layer.addTo(map);
        }
      } catch (e) {
        fail(e?.message || "Provider failed.");
      }
    })();

    return () => { cancelled = true; };
  }, [manual]);

  return (
    <div className="relative rounded-2xl overflow-hidden backdrop-blur-xl bg-black/40 ring-1 ring-white/10">
      <div className="flex items-center justify-between px-3 py-2">
        <div className="text-sm opacity-80">
          Radar {active ? `• ${PROVIDERS[active]?.label || active}` : ""}
        </div>
        <div className="flex items-center gap-2 text-xs">
          <button
            className={`px-2 py-0.5 rounded ${manual === "" ? "bg-white/20" : "bg-white/10"}`}
            onClick={() => setManual("")}
            title="Auto (fastest)"
          >
            Auto
          </button>
          <button
            className={`px-2 py-0.5 rounded ${manual === "mesonet" ? "bg-white/20" : "bg-white/10"}`}
            onClick={() => setManual("mesonet")}
          >
            Mesonet
          </button>
          <button
            className={`px-2 py-0.5 rounded ${manual === "rainviewer" ? "bg-white/20" : "bg-white/10"}`}
            onClick={() => setManual("rainviewer")}
          >
            RV
          </button>
          <button
            className={`px-2 py-0.5 rounded ${manual === "owm" ? "bg-white/20" : "bg-white/10"}`}
            onClick={() => setManual("owm")}
            disabled={!OWM_KEY}
            title={!OWM_KEY ? "Set REACT_APP_OWM_KEY / VITE_OWM_KEY" : "OpenWeather"}
          >
            OWM
          </button>
        </div>
      </div>

      <div id="radar-map" style={{ height: 320, width: "100%" }} />

      {loading && (
        <div className="absolute inset-0 grid place-items-center">
          <div className="animate-spin h-6 w-6 rounded-full border-2 border-white/30 border-t-white" />
        </div>
      )}

      {!!errorText && !loading && (
        <div className="absolute bottom-2 left-2 right-2 text-xs px-2 py-1 rounded bg-black/70 ring-1 ring-white/10">
          {errorText}
        </div>
      )}

      {/* Legend (approximate) */}
      <div className="absolute bottom-3 left-3 text-[11px] rounded bg-black/60 px-2 py-1 ring-1 ring-white/10">
        <div className="font-medium mb-1">Precip Intensity</div>
        <div className="flex items-center gap-2">
          <span className="inline-block h-2 w-6 bg-yellow-400" /> Moderate
          <span className="inline-block h-2 w-6 bg-red-500" /> Heavy
          <span className="inline-block h-2 w-6 bg-blue-400" /> Snowy areas
        </div>
      </div>
    </div>
  );
}
